macroActions.command:
// > in visual mode: indent selection
ifShift if ($mode == 2 || $mode == 3) final suppressMods tapKey LG-closingBracketAndClosingBrace
// >> in normal mode: indent line
ifShift ifGesture $thisKeyId final suppressMods tapKey LG-closingBracketAndClosingBrace
// dot repeat
if ($lastOperator == 1) {
    setVar count $lastCount

    // WORD (1)
    if ($lastMotion == 1) {
        while ($count > 0) {
            tapKeySeq LSA-right LS-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // BACK_WORD (2)
    if ($lastMotion == 2) {
        while ($count > 0) {
            tapKeySeq LSA-left
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // END_WORD (3)
    if ($lastMotion == 3) {
        while ($count > 0) {
            tapKeySeq LSA-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // LINE (4)
    if ($lastMotion == 4) {
        while ($count > 0) {
            tapKey LG-left
            tapKeySeq LSG-right
            tapKey backspace
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // TO_EOL (5)
    if ($lastMotion == 5) {
        while ($count > 0) {
            tapKeySeq LSG-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // DOWN (6)
    if ($lastMotion == 6) {
        while ($count > 0) {
            tapKey LG-left
            tapKeySeq LSG-right LS-down
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // UP (7)
    if ($lastMotion == 7) {
        while ($count > 0) {
            tapKey up
            tapKey LG-left
            tapKeySeq LSG-right LS-down
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // LEFT (8)
    if ($lastMotion == 8) {
        while ($count > 0) {
            tapKeySeq LS-left
            tapKey backspace
            setVar count ($count - 1)
        }
    }
    // RIGHT (9)
    if ($lastMotion == 9) {
        while ($count > 0) {
            tapKeySeq LS-right
            tapKey backspace
            setVar count ($count - 1)
        }
    }
}

// If count > 0, append digit 0
if ($count > 0) final setVar count ($count * 10 + 0)
// V-LINE: no-op
if ($mode == 3) final setVar count 0
// VISUAL: extend selection to start of line
if ($mode == 2) final suppressMods tapKey LSG-left
// DELETE operator: select to start then delete
if ($operator == 1) suppressMods tapKeySeq LSG-left
if ($operator == 1) suppressMods tapKey backspace
if ($operator == 1) setVar operator 0
if ($operator == 1) final setVar count 0
// NORMAL: go to start of line
suppressMods tapKey LG-left

// $ (Shift+4): end of line
// V-LINE: no-op
ifShift if ($mode == 3) final setVar count 0
// VISUAL: extend selection to end of line
ifShift if ($mode == 2) setVar count 0
ifShift if ($mode == 2) final suppressMods tapKey LSG-right
// DELETE operator + $: delete to end of line
ifShift if ($operator == 1) suppressMods tapKeySeq LSG-right
ifShift if ($operator == 1) suppressMods tapKey backspace
ifShift if ($operator == 1) setVar operator 0
ifShift if ($operator == 1) final setVar count 0
// NORMAL $: go to end of line
ifShift final suppressMods tapKey LG-right
// No shift: append digit 4
setVar count ($count * 10 + 4)

ifShift suppressMods {
    tapKey LG-right
}
else suppressMods {
    tapKey right
}

switchKeymap MIK

// C = change to end of line
ifShift final {
    suppressMods tapKeySeq LSG-right
    suppressMods tapKey backspace
    switchKeymap MIK
}
// cc = change entire line
ifGesture c final {
    suppressMods tapKey LG-left
    suppressMods tapKeySeq LSG-right
    suppressMods tapKey backspace
    switchKeymap MIK
}
// cw = change word
ifGesture w final {
    tapKeySeq LSA-right
    tapKey backspace
    switchKeymap MIK
}

noOp
// Visual mode: delete selection
if ($mode == 2 || $mode == 3) tapKey backspace
if ($mode == 2 || $mode == 3) setVar count 0
if ($mode == 2 || $mode == 3) set backlight.constantRgb.rgb 255 255 255
if ($mode == 2 || $mode == 3) final setVar mode 0
// Shift held means Vim "X", delete left
ifShift final holdKey backspace
// otherwise Vim "x", delete right
holdKey delete

if ($mode == 2 || $mode == 3)
{
    tapKey right
    setVar mode 0
    setVar operator 0
    setVar count 0
    set backlight.constantRgb.rgb 255 255 255
}
else
{
    setVar operator 0
    setVar count 0
    setVar mode 0
    tapKey escape
}

// gg: jump to ggAction (gesture consumes keypress, so only check once)
ifGesture timeoutIn 300 g goTo ggAction
// G in visual/visual-line: extend selection to bottom
ifShift if ($mode == 2 || $mode == 3) final suppressMods tapKey LSG-down
// G in normal: go to bottom
ifShift final suppressMods tapKey G-down
holdKey g
// gg landed here
ggAction:
if ($mode == 2 || $mode == 3) final suppressMods tapKey LSG-up
tapKey G-up

ifShift suppressMods {
    tapKey LG-left
}
switchKeymap MIK

ifShift suppressMods {
    tapKey LG-left
    tapKey enter
    tapKey up
    switchKeymap MIK
}
else {
    suppressMods {
        tapKey LG-right
        tapKey enter
    }
    switchKeymap MIK
}

set autoRepeatDelay 120
set autoRepeatRate 30
set secondaryRole.defaultStrategy advanced
set secondaryRole.advanced.timeout 200
set secondaryRole.advanced.timeoutAction secondary
set secondaryRole.advanced.safetyMargin 0
set secondaryRole.advanced.triggerByRelease 0
set secondaryRole.advanced.doubletapToPrimary 1
set secondaryRole.advanced.doubletapTime 200

// mode meanings:
// 0 = NORMAL   (default; motions/operators/commands)
// 1 = INSERT   (keys pass through as typing; Esc returns to NORMAL)
// 2 = VISUAL   (character selection; motions extend selection with Shift)
// 3 = VISUAL LINE (full-line selection; j/k extend by line)
// 4 = REPLACE  (optional later; like Vim R)
// 5 = COMMAND  (optional later; ":" / ex-like command entry)
setVar mode 0
// operator meanings:
// 0 = NONE
// 1 = DELETE
// 2 = YANK
setVar operator 0
// tracks the number of times to do a change (supports multi-digit like 23dw)
setVar count 0

// last executed change, used for the . key
setVar lastOperator 0
// motion meanings:
// 0 = NONE
// 1 = WORD (w)
// 2 = BACK_WORD (b)
// 3 = END_WORD (e)
// 4 = LINE (dd)
// 5 = TO_EOL (D)
// 6 = DOWN (j)
// 7 = UP (k)
// 8 = LEFT (h)
// 9 = RIGHT (l)
setVar lastMotion 0
setVar lastCount 0

ifLayer fn2 {
    untoggleLayer
    set backlight.constantRgb.rgb 255 192 32
    tapKey escape
}
else {
    toggleLayer fn2
    set backlight.constantRgb.rgb 255 0 0
}

// < in visual mode: outdent selection
ifShift if ($mode == 2 || $mode == 3) final suppressMods tapKey LG-openingBracketAndOpeningBrace
// << in normal mode: outdent line
ifShift ifGesture $thisKeyId final suppressMods tapKey LG-openingBracketAndOpeningBrace
